/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Features:
 * - Phone number resolution: resolves user IDs or identifiers to phone numbers
 * - Message truncation: SMS messages are limited to 160 characters
 * - Pluggable transport: swap InMemorySmsTransport for a real provider (Twilio, SNS, etc.)
 *
 * Follows the same three-layer pattern as EmailAdapter and WebhookAdapter:
 * 1. PhoneResolver — resolves recipient identifiers to phone numbers
 * 2. SmsTransport — abstracts SMS delivery
 * 3. SmsAdapter — implements NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Maximum length for an SMS message body.
 */
export const SMS_MAX_LENGTH = 160;

/**
 * Transport abstraction for SMS delivery.
 * Implement this interface to plug in a real SMS provider.
 */
export interface SmsTransport {
  sendSms(options: {
    to: string;
    body: string;
  }): Promise<{ messageId: string }>;
}

/**
 * A sent SMS record, for auditing and testing.
 */
export interface SentSms {
  to: string;
  body: string;
  sentAt: Date;
  messageId: string;
}

/**
 * Resolves a recipient identifier to a phone number.
 * Returns null if the recipient cannot be resolved.
 */
export type PhoneResolver = (recipient: string) => Promise<string | null>;

/**
 * Default phone resolver — treats the recipient as a phone number if it
 * starts with '+', otherwise returns null.
 */
export const defaultPhoneResolver: PhoneResolver = async (recipient: string) => {
  if (recipient.startsWith('+')) {
    return recipient;
  }
  return null;
};

/**
 * In-memory SMS transport for development and testing.
 */
export class InMemorySmsTransport implements SmsTransport {
  private nextId = 1;

  async sendSms(options: {
    to: string;
    body: string;
  }): Promise<{ messageId: string }> {
    const messageId = `sms-msg-${String(this.nextId++).padStart(4, '0')}`;
    return { messageId };
  }

  resetIdCounter(): void {
    this.nextId = 1;
  }
}

/**
 * Format a notification payload into an SMS message body.
 * Includes the subject and body, truncated to SMS_MAX_LENGTH characters.
 */
export function formatSmsBody(payload: NotificationPayload): string {
  const full = `${payload.subject}: ${payload.body}`;
  if (full.length <= SMS_MAX_LENGTH) {
    return full;
  }
  return full.slice(0, SMS_MAX_LENGTH - 3) + '...';
}

// --- SmsAdapter ---

let nextId = 1;

function generateSmsId(): string {
  return `sms-${String(nextId++).padStart(4, '0')}`;
}

export function resetSmsIdCounter(): void {
  nextId = 1;
}

export interface SmsAdapterOptions {
  transport?: SmsTransport;
  phoneResolver?: PhoneResolver;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];
  private transport: SmsTransport;
  private phoneResolver: PhoneResolver;

  constructor(options?: SmsAdapterOptions) {
    this.transport = options?.transport ?? new InMemorySmsTransport();
    this.phoneResolver = options?.phoneResolver ?? defaultPhoneResolver;
  }

  /**
   * Send an SMS notification:
   * 1. Resolve recipient to a phone number
   * 2. Format the message body (truncated to 160 chars)
   * 3. Send via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const smsId = generateSmsId();

    // Step 1: Resolve recipient
    const resolvedPhone = await this.phoneResolver(payload.recipient);
    if (!resolvedPhone) {
      this.logger.error(`Cannot resolve phone number: ${payload.recipient}`);
      return {
        success: false,
        notificationId: smsId,
        channel: 'sms',
        error: `Cannot resolve phone number: ${payload.recipient}`,
      };
    }

    // Step 2: Format message body
    const body = formatSmsBody(payload);

    this.logger.info(`Sending SMS to ${resolvedPhone}: ${payload.subject}`);

    // Step 3: Send via transport
    try {
      const result = await this.transport.sendSms({
        to: resolvedPhone,
        body,
      });

      const sms: SentSms = {
        to: resolvedPhone,
        body,
        sentAt: new Date(),
        messageId: result.messageId,
      };

      this.sentMessages.push(sms);

      return {
        success: true,
        notificationId: smsId,
        channel: 'sms',
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Transport error: ${message}`);
      return {
        success: false,
        notificationId: smsId,
        channel: 'sms',
        error: `Transport error: ${message}`,
      };
    }
  }

  /**
   * Get all sent SMS messages. Useful for testing.
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
  resetSmsIdCounter,
  formatSmsBody,
  defaultPhoneResolver,
  SMS_MAX_LENGTH,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  PhoneResolver,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    type: 'order_confirmation',
    recipient: '+15551234567',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    channel: 'sms',
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
    resetSmsIdCounter();
  });

  describe('send', () => {
    it('should send an SMS and return success', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.notificationId).toBe('sms-0001');
    });

    it('should store sent messages for inspection', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.body).toContain('Order Confirmation');
      expect(sent[0]?.messageId).toBeTruthy();
    });

    it('should generate sequential SMS IDs', async () => {
      const r1 = await adapter.send(makePayload());
      const r2 = await adapter.send(makePayload({ recipient: '+15559876543' }));

      expect(r1.notificationId).toBe('sms-0001');
      expect(r2.notificationId).toBe('sms-0002');
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should truncate long messages to SMS_MAX_LENGTH', async () => {
      const longBody = 'A'.repeat(200);
      await adapter.send(makePayload({ body: longBody }));

      const sent = adapter.getSentMessages();
      expect(sent[0]?.body.length).toBeLessThanOrEqual(SMS_MAX_LENGTH);
      expect(sent[0]?.body).toMatch(/\.\.\.$/);
    });

    it('should not truncate short messages', async () => {
      await adapter.send(makePayload({ subject: 'Hi', body: 'Done' }));

      const sent = adapter.getSentMessages();
      expect(sent[0]?.body).toBe('Hi: Done');
    });
  });

  describe('phone resolution', () => {
    it('should fail when recipient cannot be resolved to a phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: 'alice@example.com' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve phone number');
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should fail when recipient is a plain user ID', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user-123' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve phone number');
    });

    it('should use a custom phone resolver', async () => {
      const resolver: PhoneResolver = vi.fn().mockResolvedValue('+15550000000');
      const customAdapter = new SmsAdapter({ phoneResolver: resolver });
      resetSmsIdCounter();

      const result = await customAdapter.send(makePayload({ recipient: 'user-123' }));

      expect(result.success).toBe(true);
      expect(resolver).toHaveBeenCalledWith('user-123');

      const sent = customAdapter.getSentMessages();
      expect(sent[0]?.to).toBe('+15550000000');
    });
  });

  describe('error handling', () => {
    it('should handle transport errors gracefully', async () => {
      const transport: SmsTransport = {
        sendSms: vi.fn().mockRejectedValue(new Error('Service unavailable')),
      };

      const errorAdapter = new SmsAdapter({ transport });
      const result = await errorAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Service unavailable');
      expect(errorAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should handle non-Error transport throws', async () => {
      const transport: SmsTransport = {
        sendSms: vi.fn().mockRejectedValue('string error'),
      };

      const errorAdapter = new SmsAdapter({ transport });
      const result = await errorAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('string error');
    });
  });

  describe('transport', () => {
    it('should use a custom transport', async () => {
      const sendSms = vi.fn().mockResolvedValue({ messageId: 'custom-001' });
      const transport: SmsTransport = { sendSms };

      const customAdapter = new SmsAdapter({ transport });
      resetSmsIdCounter();

      await customAdapter.send(makePayload());

      expect(sendSms).toHaveBeenCalledOnce();
      expect(sendSms).toHaveBeenCalledWith({
        to: '+15551234567',
        body: expect.stringContaining('Order Confirmation'),
      });
    });
  });
});

describe('defaultPhoneResolver', () => {
  it('should resolve numbers starting with +', async () => {
    expect(await defaultPhoneResolver('+15551234567')).toBe('+15551234567');
  });

  it('should return null for email addresses', async () => {
    expect(await defaultPhoneResolver('alice@example.com')).toBeNull();
  });

  it('should return null for plain strings', async () => {
    expect(await defaultPhoneResolver('user-123')).toBeNull();
  });
});

describe('formatSmsBody', () => {
  it('should combine subject and body', () => {
    const result = formatSmsBody(makePayload());
    expect(result).toBe('Order Confirmation: Your order has been placed.');
  });

  it('should truncate to SMS_MAX_LENGTH with ellipsis', () => {
    const payload = makePayload({ body: 'X'.repeat(200) });
    const result = formatSmsBody(payload);
    expect(result.length).toBe(SMS_MAX_LENGTH);
    expect(result).toMatch(/\.\.\.$/);
  });

  it('should not truncate short messages', () => {
    const payload = makePayload({ subject: 'Hi', body: 'Ok' });
    const result = formatSmsBody(payload);
    expect(result).toBe('Hi: Ok');
    expect(result.length).toBeLessThanOrEqual(SMS_MAX_LENGTH);
  });
});

describe('InMemorySmsTransport', () => {
  it('should return a message ID', async () => {
    const transport = new InMemorySmsTransport();
    const result = await transport.sendSms({ to: '+15551234567', body: 'test' });
    expect(result.messageId).toBe('sms-msg-0001');
  });

  it('should generate sequential message IDs', async () => {
    const transport = new InMemorySmsTransport();
    const r1 = await transport.sendSms({ to: '+15551234567', body: 'test1' });
    const r2 = await transport.sendSms({ to: '+15559876543', body: 'test2' });
    expect(r1.messageId).toBe('sms-msg-0001');
    expect(r2.messageId).toBe('sms-msg-0002');
  });

  it('should reset ID counter', async () => {
    const transport = new InMemorySmsTransport();
    await transport.sendSms({ to: '+15551234567', body: 'test' });
    transport.resetIdCounter();
    const result = await transport.sendSms({ to: '+15551234567', body: 'test' });
    expect(result.messageId).toBe('sms-msg-0001');
  });
});

